head.script:
scwin.ID = $c.data.getMemInfo("userId");

scwin.onpageload = function () {
    scwin.updateMblNoUnderbar();

    const codeOptions = [
        { grpCd: "IL047", compID: "gr_SeaAFRCont:cntrOwnerCd" } //정정항목
    ];

    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function () {
    btn_vssl.hide();
    btn_carrier.hide();

    scwin.f_initSetTab();
    scwin.f_Set("INIT");

    //README : SCAC 코드명 길이제한이 20인데, DB에는 더 긴 데이터가 존재한다.
    // 그래서 바인딩 되어있는 dataList에 데이터가 길이만큼 잘려버려서 길이제한을 속성으로 주지 않고 사용자 입력으로 처리하도록 코드를 수정하였다. 
    //(사용자 입력으로는 20자 넘는 코드명칭 일 경우 추가입력 불가. 삭제만 가능)
    txt_scacNm.bind("editkeyup", scwin.txt_scacNm_editkeyupEvent);
};

scwin.cfViewTab = async function (index) {
    await tb_control.setSelectedTabIndex(index);
};

//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
    //$c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1,tr_tab_center2]);
    tb_control.enableTab(0);
    tb_control.enableTab(1);
    tb_control.enableTab(2);

    scwin.cfViewTab(0);
};

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    //console.log('gubun : ' + gubun);
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([b_Create, b_Cancel, b_Update, b_Save, b_Delete]);
            scwin.f_DisablePopUpObj();
            gr_SeaAFRCont.setReadOnly("grid", true);
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            $c.gus.cfEnableBtnOnly([b_Create]);
            $c.gus.cfDisableBtnOnly([b_Cancel, b_Update, b_Save, b_Delete]);
            scwin.f_DisablePopUpObj();
            gr_SeaAFRCont.setReadOnly("grid", true);
            gr_SeaAFR.setColumnReadOnly("chk", true); 
            break;
        case "RETRIEVE2":
            $c.gus.cfDisableKeyData();
            $c.gus.cfEnableBtnOnly([b_Update, b_Delete]);
            $c.gus.cfDisableBtnOnly([b_Cancel, b_Create, b_Save]);
            scwin.f_DisablePopUpObj();
            gr_SeaAFRCont.setReadOnly("grid", true);
            gr_SeaAFR.setColumnReadOnly("chk", false);
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableBtnOnly([b_Save, b_Cancel]);
            $c.gus.cfDisableBtnOnly([b_Delete, b_Update, b_Create]);
            scwin.f_EnablePopUpObj();
            gr_SeaAFRCont.setReadOnly("grid", false);
            gr_SeaAFR.setColumnReadOnly("chk", true);
            $c.gus.cfEnableObjects([txt_shipperNm, txt_shipperAddr1, txt_shipperAddr2, txt_shipperAddr3, txt_shipperAddr4,
                txt_consigneeNm, txt_consigneeAddr1, txt_consigneeAddr2, txt_consigneeAddr3, txt_consigneeAddr4]);// B/L 정보 수정할 수 있도록 추가
            break;
        case "UPDATE":
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableBtnOnly([b_Save, b_Delete, b_Cancel]);
            $c.gus.cfDisableBtnOnly([b_Update, b_Create]);
            scwin.f_EnablePopUpObj();
            gr_SeaAFRCont.setReadOnly("grid", false);
            gr_SeaAFR.setColumnReadOnly("chk", true);
            $c.gus.cfEnableObjects([txt_shipperNm, txt_shipperAddr1, txt_shipperAddr2, txt_shipperAddr3, txt_shipperAddr4,
                txt_consigneeNm, txt_consigneeAddr1, txt_consigneeAddr2, txt_consigneeAddr3, txt_consigneeAddr4]);// B/L 정보 수정할 수 있도록 추가
            break;
        case "DELETE":
            $c.gus.cfDisableKeyData();
            $c.gus.cfEnableBtnOnly([b_Delete]);
            $c.gus.cfDisableBtnOnly([b_Update, b_Create, b_Save, b_Cancel]);
            scwin.f_DisablePopUpObj();
            break;
    }
};

//-------------------------------------------------------------------------
// 비활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function () {
    $c.gus.cfDisableObjects([btn_callSign, btn_vsslNation, btn_scac, btn_orgPort, btn_shipperNation, btn_consigneeNation, btn_noty1Nation, btn_noty2Nation]);
    $c.gus.cfDisableObjects([ed_etd, ed_eta, udc_discPort, udc_lodPort, udc_dlv, udc_dest]);
};

//-------------------------------------------------------------------------
// 활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
    $c.gus.cfEnableObjects([btn_callSign, btn_vsslNation, btn_scac, btn_orgPort, btn_shipperNation, btn_consigneeNation, btn_noty1Nation, btn_noty2Nation]);
    $c.gus.cfDisableObjects([ed_etd, ed_eta, udc_discPort, udc_lodPort, udc_dlv, udc_dest]);
    $c.gus.cfDisableObjects([ed_vsslCd, txt_vsslNm, ed_vygNo, ed_carrierCd, txt_carrierNm]);
    $c.gus.cfDisableObjects([ed_hblno, ed_mblno2, ed_discPortCd, txt_discPortNm, ed_lodPortCd, txt_lodPortNm, ed_dlvCd, txt_dlvNm, ed_destCd, txt_destNm, ed_etd, ed_eta]);
    $c.gus.cfDisableObjects([txt_shipperNm, txt_shipperAddr1, txt_shipperAddr2, txt_shipperAddr3, txt_shipperAddr4]);
    $c.gus.cfDisableObjects([txt_consigneeNm, txt_consigneeAddr1, txt_consigneeAddr2, txt_consigneeAddr3, txt_consigneeAddr4]);
    $c.gus.cfDisableObjects([ed_pkg, lc_unitCd, txt_grossWt, txt_msr]);
};

scwin.executeSubmission = async function (sbmObj) {

    let rtn = await $c.sbm.execute(sbmObj);
    let jsonRtn = rtn.responseJSON;
    let success = jsonRtn.resultDataSet[0].Code == "0";
    switch (sbmObj.org_id) {
        case "sbm_retrieve":
            scwin.f_ByteCheck();
            break;
        case "sbm_retrieve2":
            scwin.sbm_retrieve2_submitdone(success);
            break;
        case "sbm_retrieveCont":
            break;
        case "sbm_retrieveCont2":
            scwin.sbm_retrieveCont2_submitdone(success);
            break;
        case "sbm_Save":
            scwin.sbm_Save_submitdone(success);
            break;
        case "sbm_SaveCont":
            break;
        case "sbm_edisend":
            await $c.win.alert("전송대기상태로 전환되었습니다.");
            break;
        case "sbm_SaveCallSign":
            await $c.win.alert("저장이 완료되었습니다.");
            break;
        case "sbm_retrieveMarks":
            break;
    }
};

//---------------------------------------------------------
//조회
//---------------------------------------------------------   
scwin.f_Retrieve = async function () {
    if (ed_mblno.getValue() == "") {
        await $c.win.alert("Master B/L은 필수 입력사항입니다.");
        return;
    }
    dma_Search.set("mblno", ed_mblno.getValue());
    dma_Search.set("kcomcd", "DBEX");
    await scwin.executeSubmission(sbm_retrieve);

    if (ds_SeaAFR.getCellData(0, "flag") == "1") {// BL에서 정보를 가져올때
        gr_SeaAFR.setReadOnly("grid", true);
        ed_dangUnNo.setValue("");
        lc_relaxYn.setValue("");
        lc_scpYn.setValue("");
        lc_completeYn.setValue("");
        scwin.f_Set("RETRIEVE");
    } else if (ds_SeaAFR.getCellData(0, "flag") == "2") {
        gr_SeaAFR.setReadOnly("grid", false);
        scwin.f_Set("RETRIEVE2");
    }
};

//---------------------------------------------------------
// 컨테이너 조회
//---------------------------------------------------------    
scwin.f_RetrieveCont = async function (row) {
    dma_SearchCont.set("hblno", ds_SeaAFR.getCellData(row, "hblno"));
    dma_SearchCont.set("mhno", ds_SeaAFR.getCellData(row, "mhno"));
    dma_SearchCont.set("flag", ds_SeaAFR.getCellData(row, "flag"));
    await scwin.executeSubmission(sbm_retrieveCont);
};


//---------------------------------------------------------
// 컨테이너 조회(수정)
//---------------------------------------------------------    
scwin.f_RetrieveCont2 = async function () {
    let rowPos = ds_SeaAFR.getRowPosition();
    dma_SearchCont2.set("hblno", ds_SeaAFR.getCellData(rowPos, "hblno"));
    dma_SearchCont2.set("mhno", ds_SeaAFR.getCellData(rowPos, "mhno"));
    dma_SearchCont2.set("mblno", ds_SeaAFR.getCellData(rowPos, "mblno"));
    await scwin.executeSubmission(sbm_retrieveCont2);
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = async function () {
    scwin.f_Set("CREATE");
    let rowPos = ds_SeaAFR.getRowPosition();
    ds_SeaAFR.modifyRowStatus(rowPos, "C");
    for (let i = 0; i < ds_SeaAFRCont.getRowCount(); i++) {
        ds_SeaAFRCont.modifyRowStatus(i, "C");
    }
    await scwin.f_AddrByteCheck();
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = async function () {
    let rowPos = ds_SeaAFR.getRowPosition();
    dma_Search2.set("hblno", ds_SeaAFR.getCellData(rowPos, "hblno"));
    dma_Search2.set("mblno", ds_SeaAFR.getCellData(rowPos, "mblno"));
    dma_Search2.set("mhno", ds_SeaAFR.getCellData(rowPos, "mhno"));
    dma_Search2.set("kcomcd", "DBEX");

    await scwin.executeSubmission(sbm_retrieve2);
    scwin.f_Set("UPDATE");
    ds_SeaAFR.modifyRowStatus(rowPos, "U");
};

//-------------------------------------------------------------------------
// 프로그램 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = async function () {
    await scwin.f_Retrieve();
    if (ds_SeaAFR.getCellData(0, "flag") == "2") {
        scwin.f_Set("RETRIEVE2");
    } else {
        scwin.f_Set("RETRIEVE");
    }
};

//행취소
scwin.f_undoRow = function (ds) {
    ds.undoRow(ds.getRowPosition());
};

//-------------------------------------------------------------------------
// 프로그램 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    let rowPos = ds_SeaAFR.getRowPosition();
    if (ds_SeaAFR.getCellData(rowPos, "sendYn") == "1") {
        await $c.win.alert("이미 전송이 완료된 건은 삭제할 수 없습니다.");
        ds_SeaAFR.undoAll();
        ds_SeaAFRCont.undoAll();
        return;
    }

    let chk = await $c.win.confirm(MSG_CM_CRM_004);
    if (chk) {
        ds_SeaAFR.modifyRowStatus(rowPos, "D");
        ds_SeaAFRCont.modifyAllStatus("D");

        await scwin.executeSubmission(sbm_Save);
        await scwin.executeSubmission(sbm_SaveCont);
        await scwin.f_Retrieve();
    }
};


scwin.isUpdateSeaAFRDataList = function() {
    let rowCnt = ds_SeaAFR.getRowCount();
    for(let rowIdx = 0; rowIdx<rowCnt; rowIdx++) {

        let pre = ds_SeaAFR.getOriginalRowData(rowIdx);
        let cur = ds_SeaAFR.getRowData(rowIdx);

		//pre, cur 배열의 값이 같은지 비교한다. (순서대로)
        let colCnt = pre.length;
		for(let colIdx=0; colIdx<colCnt; colIdx++) {
			if(pre[colIdx] != cur[colIdx]) {
				return true;
			}
		}

    }

    return false;
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    let rowPos = ds_SeaAFR.getRowPosition();
    if (!scwin.isUpdateSeaAFRDataList()//ds_SeaAFR.getUpdatedIndex().length == 0
        && ds_SeaAFR.getCellData(rowPos, "flag") == "2"
        && ds_SeaAFRCont.getUpdatedIndex().length == 0) {
        await $c.win.alert("변경된 내용이 없습니다.");
        return;
    }
    let checkReqField = true; //이거 동작 안함... ㅜㅜ await scwin.f_ReqFieldChk();
    if (checkReqField) {
        if (ed_callSignCd.getValue() == "" && ed_vsslNationCd.getValue() == "") {
            await $c.win.alert("CALL SIGN과 Nationality 중에서 최소한 하나의 값이 입력되어야 합니다.");
            return;
        }
        if (txt_vsslNm.getValue() == "") {
            await $c.win.alert("VESSL NAME은 필수 입력 사항입니다.");
            return;
        }
        if (ed_vygNo.getValue() == "") {
            await $c.win.alert("VOYAGE는 필수 입력 사항입니다.");
            return;
        }
        if (ed_scacCd.getValue() == "") {
            await $c.win.alert("SCAC 코드는 필수 입력 사항입니다.");
            return;
        }
        if (ed_hblno.getValue() == "") {
            await $c.win.alert("HOUSE B/L NO는 필수 입력 사항입니다.");
            return;
        }
        let test = "";
        test = ed_hblno.getValue();
        test = test.substring(0, 4);
        if (test != "DBEX") {
            await $c.win.alert("해상 수출 HOUSE B/L만 AFR신고가 가능합니다.");
            return;
        }
        if (ed_mblno2.getValue() == "") {
            await $c.win.alert("MASTER B/L NO는 필수 입력 사항입니다.");
            return;
        }
        if (ed_discPortCd.getValue() == "" || txt_discPortNm.getValue() == "") {
            await $c.win.alert("DISCHARGING 정보는 필수 입력 사항입니다.");
            return;
        }
        if (ed_lodPortCd.getValue() == "" || txt_lodPortNm.getValue() == "") {
            await $c.win.alert("LOADING 정보는 필수 입력 사항입니다.");
            return;
        }
        if (ed_etd.getValue() != "") {
            if (ed_etdh.getValue() == "") {
                await $c.win.alert("출항예정일자가 있으므로, 출항예정시간도 입력해야 합니다.");
                return;
            }
        } else {
            if (ed_etdh.getValue() != "") {
                await $c.win.alert("출항예정일자가 없으므로, 출항예정시간은 입력하지 않아야 합니다.");
                return;
            }
        }
        let time = ed_etdh.getValue();
        let hour, min;
        hour = parseInt(time / 100);
        min = time - hour * 100;
        if (hour > 23 || hour < 0 || min < 0 || min > 59) {
            await $c.win.alert("시간 형식이 잘못되었습니다.");
            return;
        }
        if (ed_orgPortCd.getValue() == "" || txt_orgPortNm.getValue() == "") {
            await $c.win.alert("FISRT LOADING(최초양륙향) 정보는 필수 입력 사항입니다.");
            return;
        }
        if (txt_shipperNm.getValue() != "" || txt_shipperAddr1.getValue() != "") {
            if (ed_shipperNationCd.getValue() == "" || txt_shipperNationNm.getValue() == "") {
                await $c.win.alert("송하인 정보가 등록된 경우에 국가코드는 필수 입력 사항입니다.");
                return;
            }
            if (txt_shipperComm.getValue() == "") {
                await $c.win.alert("송하인 정보가 등록된 경우에 전화번호는 필수 입력 사항입니다.");
                return;
            }
        } else {
            if (ed_shipperNationCd.getValue() != "" || txt_shipperNationNm.getValue() != "") {
                await $c.win.alert("송하인 정보가 등록된 경우에만 국가코드를 입력할 수 있습니다.");
                return;
            }
            if (txt_shipperComm.getValue() != "") {
                await $c.win.alert("송하인 정보가 등록된 경우에만  전화번호를 입력할 수 있습니다.");
                return;
            }
        }
        if (txt_consigneeNm.getValue() != "" || txt_consigneeAddr1.getValue() != "") {
            if (ed_consigneeNationCd.getValue() == "" || txt_consigneeNationNm.getValue() == "") {
                await $c.win.alert("수하인 정보가 등록된 경우에 국가코드는 필수 입력 사항입니다.");
                return;
            }
            if (txt_consigneeComm.getValue() == "") {
                await $c.win.alert("수하인 정보가 등록된 경우에 전화번호는 필수 입력 사항입니다.");
                return;
            }
        } else {
            if (ed_consigneeNationCd.getValue() != "" || txt_consigneeNationNm.getValue() != "") {
                await $c.win.alert("수하인 정보가 등록된 경우에만 국가코드를 입력할 수 있습니다.");
                return;
            }
            if (txt_consigneeComm.getValue() != "") {
                await $c.win.alert("수하인 정보가 등록된 경우에만 전화번호를 입력할 수 있습니다.");
                return;
            }
        }
        if (txt_noty1Nm.getValue() != "" || txt_noty1Addr1.getValue() != "") {
            if (ed_noty1NationCd.getValue() == "" || txt_noty1NationNm.getValue() == "") {
                await $c.win.alert("통지처1 정보가 등록된 경우에 국가코드는 필수 입력 사항입니다.");
                return;
            }
            if (txt_noty1Comm.getValue() == "") {
                await $c.win.alert("통지처1 정보가 등록된 경우에 전화번호는 필수 입력 사항입니다.");
                return;
            }
        } else {
            if (ed_noty1NationCd.getValue() != "" || txt_noty1NationNm.getValue() != "") {
                await $c.win.alert("통지처1 정보가 등록된 경우에만 국가코드를 입력할 수 있습니다.");
                return;
            }
            if (txt_noty1Comm.getValue() != "") {
                await $c.win.alert("통지처1 정보가 등록된 경우에만 전화번호를 입력할 수 있습니다.");
                return;
            }
        }
        if (txt_noty2Nm.getValue() != "" || txt_noty2Addr1.getValue() != "") {
            if (ed_noty2NationCd.getValue() == "" || txt_noty2NationNm.getValue() == "") {
                await $c.win.alert("통지처2 정보가 등록된 경우에 국가코드는 필수 입력 사항입니다.");
                return;
            }
        } else {
            if (ed_noty2NationCd.getValue() != "" || txt_noty2NationNm.getValue() != "") {
                await $c.win.alert("통지처2 정보가 등록된 경우에만 국가코드를 입력할 수 있습니다.");
                return;
            }
        }
        if (txt_shipperAddr1.getValue().length > 35 || txt_shipperAddr2.getValue().length > 35 || txt_shipperAddr3.getValue().length > 35 || txt_shipperAddr4.getValue().length > 35) {
            await $c.win.alert("SHIPPER ADDRESS는 35 바이트를 초과할 수 없습니다.\nHouse BL 정보 수정 후 저장 하시기 바랍니다.");
            return;
        }
        if (txt_consigneeAddr1.getValue().length > 35 || txt_consigneeAddr2.getValue().length > 35 || txt_consigneeAddr3.getValue().length > 35 || txt_consigneeAddr4.getValue().length > 35) {
            await $c.win.alert("CONSIGNEE ADDRESS는 35 바이트를 초과할 수 없습니다.\nHouse BL 정보 수정 후 저장 하시기 바랍니다.");
            return;
        }
        if (txt_noty1Addr1.getValue().length > 35 || txt_noty1Addr2.getValue().length > 35 || txt_noty1Addr3.getValue().length > 35 || txt_noty1Addr4.getValue().length > 35) {
            await $c.win.alert("NOTIFY ADDRESS는 35 바이트를 초과할 수 없습니다.");
            return;
        }
        if (txt_noty2Addr1.getValue().length > 35 || txt_noty2Addr2.getValue().length > 35 || txt_noty2Addr3.getValue().length > 35 || txt_noty2Addr4.getValue().length > 35) {
            await $c.win.alert("NOTIFY2 ADDRESS는 35 바이트를 초과할 수 없습니다.");
            return;
        }
        if (ed_pkg.getValue() == "") {
            await $c.win.alert("PKG는 필수 입력 사항입니다.");
            return;
        }
        if (lc_unitCd.getValue() == "") {
            await $c.win.alert("UNIT 코드는 필수 입력 사항입니다.");
            return;
        }
        if (txt_grossWt.getValue() == "") {
            await $c.win.alert("Weight는 필수 입력 사항입니다.");
            return;
        }
        if (txt_msr.getValue() == "") {
            await $c.win.alert("MEASURE는 필수 입력 사항입니다.");
            return;
        }
        if (ed_pkg.getValue() == "") {
            await $c.win.alert("PKG는 필수 입력 사항입니다.");
            return;
        }
        if (txt_descItem.getValue() == "") {
            await $c.win.alert("DESCRIPTION은 필수 입력 사항입니다.");
            return;
        }
        if (txt_hsCode.getValue() == "") {
            await $c.win.alert("HS CODE는 필수 입력 사항입니다.");
            return;
        }
        if (txt_mark1.getValue() == "") {
            await $c.win.alert("Marks & Numbers는 필수 입력 사항입니다.");
            return;
        }
        if (ds_SeaAFRCont.getRowCount() < 1) {
            await $c.win.alert("최소한 1개의 CNTR 정보가 존재해야 합니다.");
            return;
        }
        for (let i = 0; i < ds_SeaAFRCont.getRowCount(); i++) {
            if (ds_SeaAFRCont.getCellData(i, "cntrOwnerCd") == "") {
                await $c.win.alert("컨테이너의 소유형태(CNTR OWNERSHIP은 필수 입력 사항입니다.");
                return;
            }
        }
        for (let i = 0; i < ds_SeaAFR.getRowCount(); i++) {
            let status = ds_SeaAFR.getRowStatus(i);
            if (status == "C" || status == "D") {
                ds_SeaAFR.setCellData(i, "regId", scwin.ID);
                ds_SeaAFR.setCellData(i, "modId", scwin.ID);
            }
        }
        ds_SeaAFR.setCellData(ds_SeaAFR.getRowPosition(), "sendYn", "");
        await scwin.executeSubmission(sbm_Save);
        await scwin.f_Retrieve();
    }
};

