scwin.txt_scacNm_editkeyupEvent = function(info, e) {

    if(info.keyCode == 8) { //backspace는 무시
        return false;
    }

    //20자 제한을 여기서 처리한다.
    let oldValue = info.oldValue;
    let newValue = info.newValue;

    if(scwin.getByteLength(newValue) > 20) {
        txt_scacNm.setValue(oldValue);
        return false;
    }

    return true;
};

